    color: #4fc3f7;
    background: rgba(79, 195, 247, 0.12);
    padding: 3px 6px;
    border-radius: 6px;
    font-family: Consolas, Monaco, monospace;
    font-size: 0.9em;
    margin: 0 2px;
    border: 1px solid rgba(79, 195, 247, 0.2);
}

/* 代码块容器样式 */
.article-content :deep(pre) {
    background: #282c34;
    color: #abb2bf;
    font-family: Consolas, Monaco, monospace;
    line-height: 1.6;
    font-size: 0.95rem;
    padding: 45px 20px 20px;
    overflow-x: auto;
    border-radius: 16px;
    border: 1px solid rgba(135, 206, 235, 0.3);
    box-shadow: 0 10px 30px rgba(79, 195, 247, 0.15);
    position: relative;
}

/* 标签面板中的代码块样式 */
.article-content .md-tabs__panels :deep(pre) {
    background: #ff0000;
    color: #ff0000;
    border-radius: 0px;
}

/* 代码块装饰圆点样式（红黄绿） */
.article-content :deep(pre)::before {
    content: "";
    position: absolute;
    top: 15px;
    left: 20px;
    width: 12px;
    height: 12px;
    border-radius: 50%;
    background: #ff5f56;
    box-shadow:
        20px 0 0 #ffbd2e,
        40px 0 0 #27c93f;
    opacity: 0.8;
}

/* 代码块内的代码元素样式 */
.article-content :deep(pre code) {
    background: transparent;
    padding: 0;
    border-radius: 0;
    color: inherit;
    border: none;
    font-family: inherit;
}

/* 代码块滚动条样式 */
.article-content :deep(pre)::-webkit-scrollbar {
    height: 8px;
    background-color: #282c34;
    border-bottom-right-radius: 16px;
    border-bottom-left-radius: 16px;
}

/* 滚动条滑块样式 */
.article-content :deep(pre)::-webkit-scrollbar-thumb {
    background: #87ceeb;
    border-radius: 4px;
    cursor: pointer;
}

/* 滚动条滑块悬停样式 */
.article-content :deep(pre)::-webkit-scrollbar-thumb:hover {
    background: #4fc3f7;
}

/* 链接样式 */
.article-content :deep(a) {
    color: #4fc3f7;
    text-decoration: none;
    border-bottom: 1px solid rgba(79, 195, 247, 0.3);
    padding: 0 2px;
    transition: all 0.3s ease;
    position: relative;
    border-radius: 4px;
}

/* 链接悬停样式 */
.article-content :deep(a:hover) {
    background: rgba(79, 195, 247, 0.15);
    border-bottom-color: #4fc3f7;
    color: #4dd0e1;
}

/* 链接点击样式 */
.article-content :deep(a:active) {
    transform: translateY(1px);
}

/* 表格样式 */
.article-content :deep(table) {
    width: 100%;
    max-width: 100%;
    border-collapse: separate;
    /* 为了圆角，必须用 separate 而不是 collapse */
    border-spacing: 0;
    margin: 30px 0;
    overflow: hidden;
    border: 1px solid rgba(135, 206, 235, 0.3);
    border-radius: 12px;
    box-shadow: 0 5px 20px rgba(0, 0, 0, 0.2);
    background: #282c34;
    font-size: 0.95rem;
}

/* 表头单元格样式 */
.article-content :deep(th) {
    background: rgba(79, 195, 247, 0.1);
    color: #4fc3f7;
    font-weight: 600;
    padding: 12px 16px;
    text-align: left;
    border-bottom: 1px solid rgba(135, 206, 235, 0.2);
}

/* 表格数据单元格样式 */
.article-content :deep(td) {
    padding: 12px 16px;
    color: #abb2bf;
    border-bottom: 1px solid rgba(255, 255, 255, 0.05);
    transition: background 0.2s;
}

/* 最后一行单元格样式 */
