    margin: 30px 0;
    padding: 20px 24px;
    background: rgba(247, 0, 67, 0.05);
    border-radius: 0 12px 12px 0;
    border-left: 4px solid #f70043;
    color: #ff00a3;
    font-style: italic;
    line-height: 1.8;
    position: relative;
}

/* 引用块装饰样式 */
.article-content :deep(blockquote)::after {
    content: "Pamper";
    position: absolute;
    top: -10px;
    right: 20px;
    font-size: 6rem;
    color: rgba(79, 195, 247, 0.1);
    font-family: serif;
    pointer-events: none;
    line-height: 1;
}

/* 引用块内段落样式 */
.article-content :deep(blockquote p) {
    margin: 0;
}

/* 列表样式 */
.article-content :deep(ul),
.article-content :deep(ol) {
    padding-left: 20px;
    margin: 20px 0;
    color: #000000;
}

/* 列表项样式 */
.article-content :deep(li) {
    margin-bottom: 10px;
    line-height: 1.8;
    position: relative;
}

/* 无序列表样式 */
.article-content :deep(ul) {
    list-style: none;
}

/* 无序列表项标记样式 */
.article-content :deep(ul li::before) {
    content: "";
    position: absolute;
    left: -20px;
    top: 10px;
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background: #4fc3f7;
    box-shadow: 0 0 8px rgba(79, 195, 247, 0.6);
    transition: all 0.3s ease;
}

/* 无序列表项标记悬停样式 */
.article-content :deep(ul li:hover::before) {
    transform: scale(1.5);
    background: #4dd0e1;
}

/* 有序列表样式 */
.article-content :deep(ol) {
    list-style-type: decimal;
}

/* 有序列表项标记样式 */
.article-content :deep(ol li::marker) {
    color: #4fc3f7;
    font-weight: bold;
    font-family: Consolas, Monaco, monospace;
    font-size: 1.1em;
}

/* 一级标题样式 */
.article-content :deep(h1) {
    font-size: 2.5rem;
    font-weight: 700;
    line-height: 1.2;
    margin: 40px 0 20px;
    position: relative;
    color: #4fc3f7;
    padding-bottom: 15px;
    border-bottom: 3px solid rgba(79, 195, 247, 0.3);
}

/* 一级标题装饰样式 */
.article-content :deep(h1)::before {
    content: "Pamper";
    position: absolute;
    top: -50px;
    right: 20px;
    font-size: 6rem;
    color: rgba(255, 0, 68, 0.1);
    font-family: serif;
    pointer-events: none;
    line-height: 1;
    font-style: italic
}

/* 二级标题样式 */
.article-content :deep(h2) {
    font-size: 2rem;
    font-weight: 700;
    line-height: 1.3;
    margin: 35px 0 18px;
    position: relative;
    color: #4dd0e1;
    padding-bottom: 12px;
    border-bottom: 2px solid rgba(77, 208, 225, 0.3);
}

/* 三级标题样式 */
.article-content :deep(h3) {
    font-size: 1.6rem;
    font-weight: 600;
    line-height: 1.4;
    margin: 30px 0 15px;
    position: relative;
    color: #87ceeb;
    padding-left: 15px;
    border-left: 4px solid #87ceeb;
}

/* 四级标题样式 */
.article-content :deep(h4) {
    font-size: 1.3rem;
    font-weight: 600;
    line-height: 1.5;
    margin: 25px 0 12px;
    position: relative;
    color: #80deea;
    padding-left: 12px;
    border-left: 3px solid #80deea;
}

/* 五级标题样式 */
.article-content :deep(h5) {
    font-size: 1.1rem;
    font-weight: 600;
    line-height: 1.5;
    margin: 20px 0 10px;
    position: relative;
    color: #b2ebf2;
    padding-left: 10px;
    border-left: 2px solid #b2ebf2;
}
````

## 侧边栏

侧边栏分别有**导航栏**和文章结构的**目录栏**，让我们一个一个讲起

### 导航栏

我们需要现在`.kecare/menus/`目录下，编写结构。

这里可以查看[菜单系统](https://kecare.kecream.cn/articles/zh-CN/4ee23999)。编写完对应的结构之后，在运行生成器时，生成器会遍历目录下的`*.menu.source.ts`将其中的 `link` 修改为正确的文章路径，并生成一个`*.menu.generated.ts`

让我们编写一个导航栏的Sidebar模板

```vue
<script setup lang="ts">
// ~/components/Lsidebar.vue
import type { NavItem } from 'kecare'

defineOptions({
    name: 'Lsidebar', //定义个name，方便后续自我调用用的
})

const props = withDefaults(defineProps<{
    items: NavItem[]
    level?: number    // 该level用于渲染层级
}>(), {
    level: 0,
})

const isLinkItem = ( //类型收缩，来判断是分组项，还是链接项
    item: NavItem
): item is { text: string; link: string; level: number } => {
    return 'link' in item
} 

const paddingStyle = computed(() => {     // 每层缩进12px
    return `padding-left: ${props.level * 12}px;`
})
function keyOf(item: NavItem) { // 为每个项生成唯一key，链接项用"l:路径"，分组项用"g:标题:层级"
    return isLinkItem(item) ? `l:${item.link}` : `g:${item.text}:${props.level}`
}
</script>
<template>
    <ul class="sidebar" :style="paddingStyle">
        <li v-for="item in props.items" :key="keyOf(item)">
             <!-- 情况1: 链接项 - 直接渲染为可点击的导航链接 -->
            <!-- isLinkItem(item): 判断item是否包含link属性 -->
            <NuxtLink v-if="isLinkItem(item)" :to="item.link" class="sidebar-link">
                {{ item.text }}
            </NuxtLink>
             <!-- 情况2: 分组项 - 渲染为导航组 -->
            <div v-else class="sidebar-group">
                <!-- 分组标题文本 -->
                <span>{{ item.text }}</span>
                 	<!-- 递归渲染子导航项 -->
                    <!-- 关键点: 组件递归调用自身，传入子项列表和层级+1 -->
                    <!-- 这使得导航树可以无限层级嵌套 -->
                <Lsidebar :items="item.items" :level="props.level + 1" />
            </div>
        </li>
    </ul>
</template>
```

接下来可自行添加 div 进行额外的美化啦~让后在文章页中调用即

```vue
// ~/components/landing.vue
<template>
	<div v-if="props.navItems !== null">
        <div class='Lsidebar' v-if="props.navItems?.length">
            <Lsidebar/>         
    	</div> 
        <div v-else>
            暂无目录喵
    	</div>
    </div>
</template>
```

很简单是不是喵。

一个页面可能会有很多个导航栏，所以需要主题作者自行适配了

### 目录栏

Kecare 在进行对markdown文章处理的时候，就已经替你处理好了目录的结构。

只需要在想要出现目录栏的地方，添加 class="kecare-sidebar" 即可

````vue
// ~/components/Rsidebar.vue
<template>
	<div>
        <h3>
            目录喵
    	</h3>
        <div class="kecare-sidebar"></div>
    </div>
</template>
<style>
    在这里添加样式就好啦，class名看下方喵
</style>
````

这样就好了喵，但是 CSS样式是需要你自己补充的喵，我们生成出来的目录结构是这样的喵

```html
<ul class="toc-list">
  <!-- 顶层标题项 -->
  <li class="toc-item">
    <a class="toc-link" data-target="heading-id" title="标题文本">标题文本</a>
    
    <!-- 子标题列表（如果有子标题） -->
    <ul class="toc-sublist">
      <li class="toc-subitem">
        <a class="toc-sublink" data-target="sub-heading-id" title="子标题文本">子标题文本</a>        
        <!-- 可以继续嵌套 -->
        <ul class="toc-sublist">
          <li class="toc-subitem">
            <a class="toc-sublink" data-target="..." title="...">...</a>
          </li>
        </ul>
      </li>
    </ul>
  </li>
</ul>
```

### 关于文章页的所有组件都讲完啦，快贡献你的主题吧

